### 8. `packages/generator-rest-client/src/template.ts`

Pure functions; no I/O. Converts DMMF types to TypeScript code strings.

#### Key helper — scalar type mapping

```typescript
import type * as DMMF from '@prisma/dmmf'

function scalarToTs(type: string): string {
  switch (type) {
    case 'Int':
    case 'Float':
    case 'Decimal':
    case 'BigInt':
      return 'number'
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'Record<string, unknown>'
    case 'Bytes':
      return 'Uint8Array'
    default:
      return 'unknown'
  }
}
```

#### Field-to-TypeScript-type

```typescript
function fieldToTs(field: DMMF.Field): string {
  let base: string
  if (field.kind === 'scalar') {
    base = scalarToTs(field.type)
  } else if (field.kind === 'enum' || field.kind === 'object') {
    base = field.type
  } else {
    base = 'unknown'
  }
  return field.isList ? `${base}[]` : base
}
```

#### Enum generation

```typescript
function generateEnum(e: DMMF.DatamodelEnum): string {
  const values = e.values
    .map((v) => `  ${v.name} = '${v.dbName ?? v.name}',`)
    .join('\n')
  return `export enum ${e.name} {\n${values}\n}`
}
```

#### Model interface generation

Relation fields (`kind === 'object'`) are marked optional (REST APIs may or may not include nested data). Scalar/enum optional fields get `| null` suffix.

```typescript
function generateModelInterface(model: DMMF.Model): string {
  const lines = model.fields.map((field) => {
    if (field.kind === 'object') {
      return `  ${field.name}?: ${fieldToTs(field)}`
    }
    const tsType = fieldToTs(field)
    const suffix = field.isRequired ? '' : ' | null'
    return `  ${field.name}: ${tsType}${suffix}`
  })
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}
```

#### WhereUniqueInput type

Uses `field.isId` to locate the primary-key field. Falls back to `Record<string, unknown>` if none is found.

```typescript
function generateWhereUniqueType(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId)
  if (!idField) {
    return `export type ${model.name}WhereUniqueInput = Record<string, unknown>`
  }
  return `export type ${model.name}WhereUniqueInput = { ${idField.name}: ${scalarToTs(idField.type)} }`
}
```

#### Per-model CRUD client class

Uses `fetch` (available in Node 18+). Resource path is `/<modelName-lowercase>s` (simple pluralization; no external dep needed for a generator scaffold).

```typescript
function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const resource = `${name.toLowerCase()}s`
  const idField = model.fields.find((f) => f.isId)
  const idName = idField?.name ?? 'id'
  const whereType = `${name}WhereUniqueInput`

  return `export class ${name}Client {
  readonly #config: RestClientConfig

  constructor(config: RestClientConfig) {
    this.#config = config
  }

  async findMany(params?: { skip?: number; take?: number; where?: Partial<${name}> }): Promise<${name}[]> {
    const url = new URL(\`\${this.#config.baseUrl}/${resource}\`)
    if (params?.skip !== undefined) url.searchParams.set('skip', String(params.skip))
    if (params?.take !== undefined) url.searchParams.set('take', String(params.take))
    const response = await fetch(url.toString(), { headers: this.#config.headers })
    return response.json() as Promise<${name}[]>
  }

  async findUnique(params: { where: ${whereType} }): Promise<${name} | null> {
    const response = await fetch(
      \`\${this.#config.baseUrl}/${resource}/\${params.where.${idName}}\`,
      { headers: this.#config.headers },
    )
    if (response.status === 404) return null
    return response.json() as Promise<${name}>
  }

  async create(params: { data: Omit<${name}, '${idName}'> }): Promise<${name}> {
    const response = await fetch(\`\${this.#config.baseUrl}/${resource}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', ...this.#config.headers },
      body: JSON.stringify(params.data),
    })
    return response.json() as Promise<${name}>
  }

  async update(params: { where: ${whereType}; data: Partial<Omit<${name}, '${idName}'>> }): Promise<${name}> {
    const response = await fetch(
      \`\${this.#config.baseUrl}/${resource}/\${params.where.${idName}}\`,
      {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json', ...this.#config.headers },
        body: JSON.stringify(params.data),
      },
    )
    return response.json() as Promise<${name}>
  }

  async delete(params: { where: ${whereType} }): Promise<${name}> {
    const response = await fetch(
      \`\${this.#config.baseUrl}/${resource}/\${params.where.${idName}}\`,
      { method: 'DELETE', headers: this.#config.headers },
    )
    return response.json() as Promise<${name}>
  }
}`
}
```

#### Root `PrismaRestClient` orchestrator

```typescript
function generateMainClient(models: readonly DMMF.Model[]): string {
  const getters = models
    .map((m) => {
      const prop = m.name.charAt(0).toLowerCase() + m.name.slice(1)
      return `  get ${prop}(): ${m.name}Client {\n    return new ${m.name}Client(this.#config)\n  }`
    })
    .join('\n\n')

  return `export class PrismaRestClient {
  readonly #config: RestClientConfig

  constructor(config: RestClientConfig) {
    this.#config = config
  }

${getters}
}`
}
```

#### Top-level export

```typescript
export function generateRestClient(
  models: readonly DMMF.Model[],
  enums: readonly DMMF.DatamodelEnum[],
): string {
  const parts: string[] = []

  parts.push(
    '// This file was auto-generated by @prisma/generator-rest-client.',
    '// Do not edit it manually.',
    '/* eslint-disable */',
    '',
  )

  for (const e of enums) {
    parts.push(generateEnum(e), '')
  }

  for (const model of models) {
    parts.push(generateModelInterface(model), '')
  }

  parts.push(
    'export interface RestClientConfig {',
    '  baseUrl: string',
    '  headers?: Record<string, string>',
    '}',
    '',
  )

  for (const model of models) {
    parts.push(generateWhereUniqueType(model))
  }
  parts.push('')

  for (const model of models) {
    parts.push(generateModelClient(model), '')
  }

  parts.push(generateMainClient(models), '')

  return parts.join('\n')
}
```

