       provider = "node packages/generator-rest-client/dist/index.js"
       output   = "./generated/rest-client"
     }
     ```
   - Run `prisma generate --schema=schema.prisma`.
   - Confirm `./generated/rest-client/rest-client.ts` is created with correct interfaces and client classes.

4. **Type-check the generated output**: `tsc --noEmit generated/rest-client/rest-client.ts`
