/** Prepends `#!/usr/bin/env node` to the bundled output and marks it executable. */
const shebangPlugin: esbuild.Plugin = {
  name: 'shebang-plugin',
  setup(b) {
    b.onEnd(async () => {
      const file = './dist/index.js'
      const content = await fs.promises.readFile(file, 'utf-8')
      await fs.promises.writeFile(file, `#!/usr/bin/env node\n${content}`)
      const stat = fs.statSync(file)
      const newMode = stat.mode | 0o111
      fs.chmodSync(file, newMode.toString(8).slice(-3))
    })
  },
}

