  {
    name: 'generator-rest-client',
    format: 'cjs',
    bundle: true,
    entryPoints: ['src/index.ts'],
    outfile: 'dist/index',
    outExtension: { '.js': '.js' },
    emitTypes: true,
    plugins: [shebangPlugin],
  },
])

