import type * as DMMF from '@prisma/dmmf'

/** Maps a Prisma scalar type name to its TypeScript equivalent. */
function scalarToTs(type: string): string {
  switch (type) {
    case 'Int':
    case 'Float':
    case 'Decimal':
    case 'BigInt':
      return 'number'
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'Record<string, unknown>'
    case 'Bytes':
      return 'Uint8Array'
    default:
      return 'unknown'
  }
}

/** Returns the TypeScript base type for a DMMF field (without list brackets or nullability). */
function fieldToTs(field: DMMF.Field): string {
  let base: string
  if (field.kind === 'scalar') {
    base = scalarToTs(field.type)
  } else if (field.kind === 'enum' || field.kind === 'object') {
    base = field.type
  } else {
    base = 'unknown'
  }
  return field.isList ? `${base}[]` : base
}

function generateEnum(e: DMMF.DatamodelEnum): string {
  const values = e.values.map((v) => `  ${v.name} = '${v.dbName ?? v.name}',`).join('\n')
  return `export enum ${e.name} {\n${values}\n}`
}

/**
 * Generates a TypeScript interface for a Prisma model.
 *
 * Relation fields are optional because REST APIs may or may not inline nested
 * data. Scalar/enum fields that are not required get a `| null` suffix.
 */
function generateModelInterface(model: DMMF.Model): string {
  const lines = model.fields.map((field) => {
    if (field.kind === 'object') {
      return `  ${field.name}?: ${fieldToTs(field)}`
    }
    const tsType = fieldToTs(field)
    const suffix = field.isRequired ? '' : ' | null'
    return `  ${field.name}: ${tsType}${suffix}`
  })
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/**
 * Generates a `WhereUniqueInput` type scoped to the model's `@id` field.
 * Falls back to `Record<string, unknown>` for models without a single-column
 * primary key (e.g., composite keys).
