function generateWhereUniqueType(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId)
  if (!idField) {
    return `export type ${model.name}WhereUniqueInput = Record<string, unknown>`
  }
  return `export type ${model.name}WhereUniqueInput = { ${idField.name}: ${scalarToTs(idField.type)} }`
}

/**
 * Generates a typed CRUD client class for a single Prisma model.
 *
 * Assumes a REST API with conventional resource paths (`/<modelName-lowercase>s`).
 * Uses the native `fetch` API (available in Node 18+).
