function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const resource = `${name.toLowerCase()}s`
  const idField = model.fields.find((f) => f.isId)
  const idName = idField?.name ?? 'id'
  const whereType = `${name}WhereUniqueInput`

  return `export class ${name}Client {
  readonly #config: RestClientConfig

  constructor(config: RestClientConfig) {
    this.#config = config
  }

  async findMany(params?: { skip?: number; take?: number; where?: Partial<${name}> }): Promise<${name}[]> {
