    if (params?.skip !== undefined) url.searchParams.set('skip', String(params.skip))
    if (params?.take !== undefined) url.searchParams.set('take', String(params.take))
    const response = await fetch(url.toString(), { headers: this.#config.headers })
    return response.json() as Promise<${name}[]>
  }

  async findUnique(params: { where: ${whereType} }): Promise<${name} | null> {
    const response = await fetch(
      \`\${this.#config.baseUrl}/${resource}/\${params.where.${idName}}\`,
      { headers: this.#config.headers },
    )
    if (response.status === 404) return null
    return response.json() as Promise<${name}>
  }

  async create(params: { data: Omit<${name}, '${idName}'> }): Promise<${name}> {
    const response = await fetch(\`\${this.#config.baseUrl}/${resource}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', ...this.#config.headers },
      body: JSON.stringify(params.data),
    })
    return response.json() as Promise<${name}>
  }

  async update(params: { where: ${whereType}; data: Partial<Omit<${name}, '${idName}'>> }): Promise<${name}> {
    const response = await fetch(
      \`\${this.#config.baseUrl}/${resource}/\${params.where.${idName}}\`,
      {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json', ...this.#config.headers },
        body: JSON.stringify(params.data),
      },
    )
    return response.json() as Promise<${name}>
  }

  async delete(params: { where: ${whereType} }): Promise<${name}> {
    const response = await fetch(
      \`\${this.#config.baseUrl}/${resource}/\${params.where.${idName}}\`,
      { method: 'DELETE', headers: this.#config.headers },
    )
    return response.json() as Promise<${name}>
  }
