/**
 * Generates the full content of `rest-client.ts` from Prisma DMMF data.
 *
 * The output is a self-contained TypeScript file containing:
 * - Enum declarations
 * - Model interfaces
 * - Per-model CRUD client classes (using `fetch`)
 * - A root `PrismaRestClient` orchestrator with typed accessors
 */
export function generateRestClient(
  models: readonly DMMF.Model[],
  enums: readonly DMMF.DatamodelEnum[],
): string {
  const parts: string[] = []

  parts.push(
    '// This file was auto-generated by @prisma/generator-rest-client.',
    '// Do not edit it manually.',
    '/* eslint-disable */',
    '',
  )

  for (const e of enums) {
    parts.push(generateEnum(e), '')
  }

  for (const model of models) {
    parts.push(generateModelInterface(model), '')
  }

  parts.push('export interface RestClientConfig {', '  baseUrl: string', '  headers?: Record<string, string>', '}', '')

  for (const model of models) {
    parts.push(generateWhereUniqueType(model))
  }
  parts.push('')

  for (const model of models) {
    parts.push(generateModelClient(model), '')
  }

  parts.push(generateMainClient(models), '')

  return parts.join('\n')
}

